def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        if ratio > 2:
            priority = ratio ** 3 - 2 * ratio
            for m in range(1, int(np.floor(ratio)) + 1):
                priority += ((ratio - m) ** 1.5) / (m + 1)
            if bin_cap % 2 == 0:
                priority *= 1.1
            else:
                priority *= 0.9
        elif 1 < ratio <= 2:
            priority = (ratio - 1) * 10
            for n in range(5):
                if (n + i) % 2 == 0:
                    priority += np.sin(ratio * np.pi * (n + 1))
                else:
                    priority -= np.cos(ratio * np.pi * (n + 1))
            priority = abs(priority)
        elif 0.25 < ratio <= 1:
            priority = -np.log(ratio) * 3
            for k in range(1, 6):
                priority += ((0.5 - ratio) ** k) * k * 0.2
            if ratio < 0.5:
                priority *= 0.8
            else:
                priority *= 1.2
            if i % 3 == 0:
                priority += bin_cap % 4
        else:
            priority = 2 - ratio * 5
            for q in range(1, 5):
                priority += ((0.25 - ratio) ** q) / q
            if priority < 0:
                priority = abs(priority) + 1
            if bin_cap > 10:
                priority /= 2
            else:
                priority *= 1.5
        priorities[i] = priority
    return priorities
